INSERT INTO `expense_patterns` VALUES (1,'monthly','ລາຍຈ່າຍປະຈຳເດືອນ','ຄິດໄລ່ຈາກ ຕໍ່ເດືອນ ຄູນ ຈ/ນ.',1,'2026-06-05 00:00:00','2026-06-05 00:00:00'),(2,'unit_quantity','ລາຍຈ່າຍຕາມລາຄາຕໍ່ໜ່ວຍ ແລະ ຈຳນວນ','ຄິດໄລ່ຈາກ ລາຄາຕໍ່ໜ່ວຍ ຄູນ ຈຳນວນ.',1,'2026-06-05 00:00:00','2026-06-05 00:00:00'),(3,'unit_quantity_frequency','ລາຍຈ່າຍຕາມລາຄາ, ຈຳນວນ ແລະ ຈຳນວນຄັ້ງ','ຄິດໄລ່ຈາກ ລາຄາຕໍ່ໜ່ວຍ ຄູນ ຈຳນວນ ຄູນ ຈຳນວນຄັ້ງ.',1,'2026-06-05 00:00:00','2026-06-05 00:00:00'),(4,'frequency_based','ລາຍຈ່າຍຕາມຈຳນວນເດືອນ ຫຼື ຈຳນວນຄັ້ງ','ຄິດໄລ່ຈາກ ລາຄາ ຄູນ ຈຳນວນ ຄູນ ເດືອນ/ຄັ້ງ.',1,'2026-06-05 00:00:00','2026-06-05 00:00:00'),(5,'event_based','ລາຍຈ່າຍກິດຈະກຳ','ຄິດໄລ່ຈາກ ລາຄາ/ຫົວໜ່ວຍ ຄູນ ຈຳນວນຄັ້ງ ຄູນ ຈຳນວນຄົນ.',1,'2026-06-05 00:00:00','2026-06-05 00:00:00');
